const express = require('express');
const helmet = require('helmet');         // Security headers
const rateLimit = require('express-rate-limit'); // Rate limiting
const { query, validationResult } = require('express-validator'); // Input validation
const cors = require('cors');

const app = express();

// --- Security Middleware ---
app.use(helmet());                        // Sets secure HTTP headers
app.use(cors({ origin: process.env.ALLOWED_ORIGINS?.split(',') || [] }));
app.use(express.json({ limit: '10kb' })); // Body parsing with size limit
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Rate limiting — 100 requests per 15 minutes per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// --- Disable fingerprinting ---
app.disable('x-powered-by');

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users',
  // Input validation for optional query params
  query('id').optional().isInt({ min: 1 }).toInt(),
  query('name').optional().isString().trim().escape(),
  (req, res, next) => {
    try {
      // Check for validation errors
      const errors = validationResult(req);
      if (!errors.isEmpty()) {
        return res.status(400).json({ errors: errors.array() });
      }

      const users = [
        { id: 1, name: 'Alice' },  // Emails removed — require auth to access
        { id: 2, name: 'Bob' },
      ];

      // Example filtering with validated input
      let result = users;
      if (req.query.id) {
        result = result.filter(u => u.id === req.query.id);
      }

      res.json(result);
    } catch (err) {
      next(err); // Forward to global error handler
    }
  }
);

// --- 404 handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global error handler (must have 4 params) ---
app.use((err, req, res, next) => {
  console.error(err.stack); // Log full error server-side
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'   // Generic message in production
      : err.message,              // Detailed message in development
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

