const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const morgan = require('morgan');

const app = express();
const PORT = process.env.PORT || 3000;

// ---------------------
// Security Middleware
// ---------------------

// Set security-related HTTP headers (XSS protection, HSTS, etc.)
app.use(helmet());

// Parse JSON bodies with a size limit to prevent large-payload DoS
app.use(express.json({ limit: '10kb' }));

// Parse URL-encoded bodies with a size limit
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Rate limiting — prevent brute-force and abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Request logging for auditing and debugging
app.use(morgan('combined'));

// Disable the X-Powered-By header to avoid fingerprinting
app.disable('x-powered-by');

// ---------------------
// Routes
// ---------------------

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (_req, res) => {
  // In production: authenticate the request, paginate results,
  // and avoid exposing sensitive fields like email without authorization.
  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  const sanitized = users.map(({ id, name }) => ({ id, name }));
  res.json(sanitized);
});

// ---------------------
// 404 Handler
// ---------------------

app.use((_req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// ---------------------
// Global Error Handler
// ---------------------

// Express requires all 4 parameters to recognize this as an error handler.
// eslint-disable-next-line no-unused-vars
app.use((err, _req, res, _next) => {
  // Log the full error server-side for debugging
  console.error('Unhandled error:', err);

  // Never leak stack traces or internal details to the client
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'
      : err.message,
  });
});

// ---------------------
// Server Start
// ---------------------

if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
  });
}

module.exports = app;

