const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();
const PORT = process.env.PORT || 3000;

// --- Security middleware ---

// Set security-related HTTP headers (removes X-Powered-By, adds CSP, HSTS, etc.)
app.use(helmet());

// Parse JSON bodies with a size limit to prevent large-payload DoS
app.use(express.json({ limit: '10kb' }));

// Parse URL-encoded bodies with a size limit
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Rate limiting: max 100 requests per 15-minute window per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// --- Routes ---

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Sample user data (would come from a database in production)
const users = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob', email: 'bob@example.com' },
];

app.get('/users', (req, res) => {
  // Validate optional query parameter `id`
  const { id } = req.query;

  if (id !== undefined) {
    const numericId = Number(id);

    if (!Number.isInteger(numericId) || numericId <= 0) {
      return res.status(400).json({ error: 'Parameter "id" must be a positive integer.' });
    }

    const user = users.find((u) => u.id === numericId);
    if (!user) {
      return res.status(404).json({ error: 'User not found.' });
    }

    return res.json(user);
  }

  return res.json(users);
});

// --- 404 handler for undefined routes ---
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found.' });
});

// --- Global error handler ---
// Prevents leaking stack traces or internal details to the client
app.use((err, _req, res, _next) => {
  console.error('Unhandled error:', err.message);
  const statusCode = err.status || 500;
  res.status(statusCode).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error.'
      : err.message,
  });
});

// --- Server startup ---
if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
  });
}

module.exports = app;

